SET json = jsonb_set(
    jsonb_set(
        json,
        '{executorConfiguration,asyncJobAcquisitionInterval}',
        '60000',
        true
    ),
    '{executorConfiguration,timerJobAcquisitionInterval}',
    '60000',
    true
)
WHERE configtype = 'workflowSettings'
  AND json->'executorConfiguration' IS NOT NULL;

